14	use zenoh_buffers::{
15	    reader::{DidntRead, Reader},
16	    writer::{DidntWrite, Writer},
17	};
18	
19	use crate::{LCodec, RCodec, WCodec, Zenoh080, Zenoh080Bounded};
20	
21	const VLE_LEN_MAX: usize = vle_len(u64::MAX);
22	
23	const fn vle_len(x: u64) -> usize {
24	    const B1: u64 = u64::MAX << 7;
25	    const B2: u64 = u64::MAX << (7 * 2);
26	    const B3: u64 = u64::MAX << (7 * 3);
27	    const B4: u64 = u64::MAX << (7 * 4);
28	    const B5: u64 = u64::MAX << (7 * 5);
29	    const B6: u64 = u64::MAX << (7 * 6);
30	    const B7: u64 = u64::MAX << (7 * 7);
31	    const B8: u64 = u64::MAX << (7 * 8);
32	
33	    if (x & B1) == 0 {
34	        1
35	    } else if (x & B2) == 0 {
36	        2
37	    } else if (x & B3) == 0 {
38	        3
39	    } else if (x & B4) == 0 {
40	        4
41	    } else if (x & B5) == 0 {
42	        5
43	    } else if (x & B6) == 0 {
44	        6
45	    } else if (x & B7) == 0 {
46	        7
47	    } else if (x & B8) == 0 {
48	        8
49	    } else {
50	        9
51	    }
52	}
53	
54	impl LCodec<u64> for Zenoh080 {
55	    fn w_len(self, x: u64) -> usize {
56	        vle_len(x)
57	    }
58	}
59	
60	impl LCodec<usize> for Zenoh080 {
61	    fn w_len(self, x: usize) -> usize {
62	        self.w_len(x as u64)
63	    }
64	}
