236	            fn write(self, writer: &mut W, x: $zint) -> Self::Output {
237	                if (x as u64 & !(<$bound>::MAX as u64)) != 0 {
238	                    return Err(DidntWrite);
239	                }
240	                Zenoh080.write(writer, x as u64)
241	            }
242	        }
