245	        where
246	            R: Reader,
247	        {
248	            type Error = DidntRead;
249	
250	            #[inline(always)]
251	            fn read(self, reader: &mut R) -> Result<$zint, Self::Error> {
252	                let x: u64 = Zenoh080.read(reader)?;
253	                if (x & !(<$bound>::MAX as u64)) != 0 {
254	                    return Err(DidntRead);
255	                }
256	                Ok(x as $zint)
257	            }
258	        }
259	    };
