102	        let header: u8 = self.codec.read(&mut *reader)?;
103	
104	        let codec = Zenoh080Header::new(header);
105	        let mut msg: NetworkMessage = codec.read(&mut *reader)?;
106	        msg.reliability = self.reliability;
107	        Ok(msg)
108	    }
