        };

        // Extensions
        let mut has_ext = imsg::has_flag(self.header, subscriber::flag::Z);
        while has_ext {
            let ext: u8 = self.codec.read(&mut *reader)?;
            has_ext = extension::skip(reader, "DeclareSubscriber", ext)?;
