        // Header
        let mut header = declare::id::U_SUBSCRIBER;
        if !ext_wire_expr.is_null() {
            header |= subscriber::flag::Z;
        }
        self.write(&mut *writer, header)?;

        // Body
        self.write(&mut *writer, id)?;

        // Extension
        if !ext_wire_expr.is_null() {
